class Solution {
    public boolean digitCount(String num) {
        int[] count = new int[10];
        for (int i = 0; i < num.length(); i++) {
            count[num.charAt(i) - '0']++;
        }
        for (int i = 0; i < num.length(); i++) {
            if (count[num.charAt(i) - '0'] != num.length() - i) {
                return false;
            }
        }
        return true;
    }
}
```

